    for (const [, tc] of toolCalls) {
      let input: unknown = {};
      try {
        input = tc.args ? JSON.parse(tc.args) : {};
      } catch {
        logger.warn("Malformed stream tool call arguments", { args: tc.args });
      }
      yield { type: "tool_use", id: tc.id, name: tc.name, input };
    }

